/*! loadpage-role-guard.min.js (cleaned) */
(function(){
  'use strict';
  window.loadAdminPage = function(pageName){
    try {
      var role = localStorage.getItem('user_role') || 'guest';
      if(role !== 'admin'){ return; } // 무반응
      var iframe = document.getElementById('mainFrame');
      var url = '/admin/' + pageName + '.html';
      fetch(url, {method:'HEAD'}).then(r=>{
        if(r.ok){ iframe.src = url; }
        else {
          var enUrl = '/en/admin/' + pageName + '.html';
          fetch(enUrl, {method:'HEAD'}).then(r2=>{
            if(r2.ok){ iframe.src = enUrl; }
            else { iframe.src = '/404.html'; }
          });
        }
      });
    } catch(_){}
  };
})();